import React, { useState, useEffect } from 'react';
import api from '../../services/api';
import FileUploader from '../../components/Admin/FileUploader';
import { Trash2, Edit, Plus, GripVertical, ChevronUp, ChevronDown } from 'lucide-react';

const BASE_URL = 'http://localhost:5000';

const SliderManager = () => {
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [saving, setSaving] = useState(false);

  // Form state
  const [title, setTitle] = useState('');
  const [subtitle, setSubtitle] = useState('');
  const [description, setDescription] = useState('');
  const [buttonText, setButtonText] = useState('');
  const [buttonLink, setButtonLink] = useState('');
  const [mediaType, setMediaType] = useState('image');
  const [file, setFile] = useState(null);

  const fetchItems = async () => {
    try {
      const { data } = await api.get('/slider');
      setItems(data);
    } catch (error) {
      console.error('Error fetching slider items:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchItems();
  }, []);

  const resetForm = () => {
    setTitle('');
    setSubtitle('');
    setDescription('');
    setButtonText('');
    setButtonLink('');
    setMediaType('image');
    setFile(null);
    setEditingId(null);
    setShowForm(false);
  };

  const openEdit = (item) => {
    setEditingId(item._id);
    setTitle(item.title || '');
    setSubtitle(item.subtitle || '');
    setDescription(item.description || '');
    setButtonText(item.buttonText || '');
    setButtonLink(item.buttonLink || '');
    setMediaType(item.mediaType || 'image');
    setFile(null);
    setShowForm(true);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);

    const formData = new FormData();
    formData.append('title', title);
    formData.append('subtitle', subtitle);
    formData.append('description', description);
    formData.append('buttonText', buttonText);
    formData.append('buttonLink', buttonLink);
    formData.append('mediaType', mediaType);
    if (file) {
      formData.append('media', file);
    }

    try {
      if (editingId) {
        await api.put(`/slider/${editingId}`, formData, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
      } else {
        await api.post('/slider', formData, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
      }
      resetForm();
      fetchItems();
    } catch (error) {
      console.error('Error saving slider item:', error);
      alert('Error saving slider item');
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this slider item?')) {
      try {
        await api.delete(`/slider/${id}`);
        setItems(items.filter(item => item._id !== id));
      } catch (error) {
        console.error('Error deleting slider item:', error);
      }
    }
  };

  const moveItem = async (index, direction) => {
    const newItems = [...items];
    const swapIndex = index + direction;
    if (swapIndex < 0 || swapIndex >= newItems.length) return;

    [newItems[index], newItems[swapIndex]] = [newItems[swapIndex], newItems[index]];
    setItems(newItems);

    try {
      await api.put('/slider/reorder', {
        orderedIds: newItems.map(item => item._id)
      });
    } catch (error) {
      console.error('Error reordering:', error);
      fetchItems(); // Revert on error
    }
  };

  if (loading) return <div>Loading slider items...</div>;

  return (
    <div>
      <div className="flex justify-between items-center mb-8">
        <h1 className="text-3xl font-serif font-bold">Homepage Slider</h1>
        <button
          onClick={() => { resetForm(); setShowForm(true); }}
          className="bg-black text-white px-4 py-2 rounded flex items-center gap-2 hover:bg-gray-dark transition-colors"
        >
          <Plus size={18} />
          <span>Add Slide</span>
        </button>
      </div>

      {/* Form */}
      {showForm && (
        <div className="bg-white p-6 rounded-lg border border-border shadow-sm mb-8">
          <h2 className="text-lg font-medium mb-4">
            {editingId ? 'Edit Slide' : 'New Slide'}
          </h2>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-sm font-medium mb-2">Title</label>
              <input
                type="text"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                required
                className="w-full p-3 border border-border rounded focus:outline-none focus:border-black transition-colors"
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium mb-2">Subtitle</label>
                <input
                  type="text"
                  value={subtitle}
                  onChange={(e) => setSubtitle(e.target.value)}
                  className="w-full p-3 border border-border rounded focus:outline-none focus:border-black transition-colors"
                />
              </div>
              <div>
                <label className="block text-sm font-medium mb-2">Media Type</label>
                <select
                  value={mediaType}
                  onChange={(e) => setMediaType(e.target.value)}
                  className="w-full p-3 border border-border rounded focus:outline-none focus:border-black transition-colors"
                >
                  <option value="image">Image</option>
                  <option value="video">Video</option>
                </select>
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium mb-2">Description</label>
              <textarea
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                rows="3"
                className="w-full p-3 border border-border rounded focus:outline-none focus:border-black transition-colors resize-y"
              ></textarea>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium mb-2">Button Text</label>
                <input
                  type="text"
                  value={buttonText}
                  onChange={(e) => setButtonText(e.target.value)}
                  className="w-full p-3 border border-border rounded focus:outline-none focus:border-black transition-colors"
                />
              </div>
              <div>
                <label className="block text-sm font-medium mb-2">Button Link</label>
                <input
                  type="text"
                  value={buttonLink}
                  onChange={(e) => setButtonLink(e.target.value)}
                  className="w-full p-3 border border-border rounded focus:outline-none focus:border-black transition-colors"
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium mb-2">Media File</label>
              <FileUploader
                onFileSelect={(f) => setFile(f)}
                accept={mediaType === 'video' ? 'video/*' : 'image/*'}
              />
            </div>

            <div className="flex gap-4 pt-4 border-t border-border">
              <button
                type="submit"
                disabled={saving}
                className="bg-black text-white px-6 py-2 rounded hover:bg-gray-dark transition-colors disabled:opacity-50"
              >
                {saving ? 'Saving...' : (editingId ? 'Update Slide' : 'Add Slide')}
              </button>
              <button
                type="button"
                onClick={resetForm}
                className="bg-white text-black border border-border px-6 py-2 rounded hover:bg-gray-light transition-colors"
              >
                Cancel
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Items List */}
      <div className="bg-white border border-border rounded-lg overflow-hidden">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-gray-light text-gray-dark text-sm uppercase tracking-wider">
              <th className="p-4 font-medium border-b border-border w-12">Order</th>
              <th className="p-4 font-medium border-b border-border w-20">Media</th>
              <th className="p-4 font-medium border-b border-border">Title</th>
              <th className="p-4 font-medium border-b border-border">Type</th>
              <th className="p-4 font-medium border-b border-border text-right">Actions</th>
            </tr>
          </thead>
          <tbody>
            {items.length === 0 ? (
              <tr>
                <td colSpan="5" className="p-8 text-center text-gray-dark">No slider items yet. Add one!</td>
              </tr>
            ) : (
              items.map((item, index) => (
                <tr key={item._id} className="hover:bg-gray-50 transition-colors">
                  <td className="p-4 border-b border-border">
                    <div className="flex flex-col gap-1">
                      <button
                        onClick={() => moveItem(index, -1)}
                        disabled={index === 0}
                        className="text-gray-dark hover:text-black disabled:opacity-20"
                      >
                        <ChevronUp size={16} />
                      </button>
                      <button
                        onClick={() => moveItem(index, 1)}
                        disabled={index === items.length - 1}
                        className="text-gray-dark hover:text-black disabled:opacity-20"
                      >
                        <ChevronDown size={16} />
                      </button>
                    </div>
                  </td>
                  <td className="p-4 border-b border-border">
                    <div className="w-16 h-12 bg-gray-light rounded overflow-hidden">
                      {item.mediaType === 'video' ? (
                        <video src={`${BASE_URL}${item.mediaUrl}`} className="w-full h-full object-cover" muted />
                      ) : (
                        <img src={`${BASE_URL}${item.mediaUrl}`} alt={item.title} className="w-full h-full object-cover" />
                      )}
                    </div>
                  </td>
                  <td className="p-4 border-b border-border font-medium">{item.title}</td>
                  <td className="p-4 border-b border-border text-gray-dark capitalize">{item.mediaType}</td>
                  <td className="p-4 border-b border-border text-right space-x-3">
                    <button onClick={() => openEdit(item)} className="inline-block text-blue-600 hover:text-blue-800">
                      <Edit size={18} />
                    </button>
                    <button onClick={() => handleDelete(item._id)} className="text-red-600 hover:text-red-800">
                      <Trash2 size={18} />
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default SliderManager;
